const isWebhook = $json.headers !== undefined || $json.body !== undefined;
let tags = [];
let buildId = null;
let source = 'schedule';
let testSource = 'sheet';
if (isWebhook) {
  source = 'webhook';
  tags = ($json.body && $json.body.tags) || [];
  buildId = ($json.body && $json.body.build_id) || null;
  testSource = ($json.body && $json.body.test_source) || 'sheet';
}
return { json: { source, tags, build_id: buildId, test_source: testSource } };

const run = $('Initialize Run').first().json;
const tagFilter = run.tags || [];
const requiredByType = {
  api: ['endpoint', 'method'],
  db: ['db_query'],
  ui: ['ui_runner_webhook', 'ui_script_id']
};
const valid = [];
const skipped = [];

function parseMaybeJson(val) {
  if (typeof val !== 'string') return val;
  try { return JSON.parse(val); } catch (e) { return val; }
}

for (const item of $input.all()) {
  const row = { ...item.json };
  row.expected_schema = parseMaybeJson(row.expected_schema);
  row.expected_key_values = parseMaybeJson(row.expected_key_values) || {};
  row.headers = parseMaybeJson(row.headers);
  row.body = parseMaybeJson(row.body);
  row.dynamic_fields = typeof row.dynamic_fields === 'string'
    ? row.dynamic_fields.split(',').map(s => s.trim()).filter(Boolean)
    : (row.dynamic_fields || []);

  if (String(row.active).toLowerCase() !== 'true') continue;
  if (tagFilter.length) {
    const rowTags = Array.isArray(row.tags) ? row.tags : String(row.tags || '').split(',').map(t => t.trim());
    if (!rowTags.some(t => tagFilter.includes(t))) continue;
  }
  const req = requiredByType[row.test_type] || [];
  const missing = req.filter(f => !row[f]);
  if (missing.length) {
    skipped.push({ test_id: row.test_id, reason: `missing fields: ${missing.join(', ')}` });
    continue;
  }
  valid.push({ ...row, run_id: run.run_id, source: run.source, build_id: run.build_id });
}

const staticData = $getWorkflowStaticData('node');
staticData.skipped = skipped;

return valid.map(v => ({ json: v }));

const item = $json;
let actual = {};
if (item.test_type === 'api') {
  actual = { status: item.statusCode ?? item.status, body: item.body ?? item.data ?? {}, latency_ms: item.headers ? item.headers['x-response-time'] : null };
} else if (item.test_type === 'db') {
  actual = { status: null, body: Array.isArray(item) ? item[0] : item, latency_ms: null };
} else if (item.test_type === 'ui') {
  actual = { status: item.status ?? item.statusCode, body: item.body ?? item, latency_ms: null };
} else {
  actual = { status: null, body: null, latency_ms: null, unsupported: true };
}
return { json: { ...item, actual } };

const t = $json;
const mismatches = [];
const dynamic = new Set(t.dynamic_fields || []);

function get(obj, path) {
  return path.split('.').reduce((o,k)=> (o||{})[k], obj);
}

function validateSchema(schema, body) {
  const errors = [];
  if (!schema || typeof schema !== 'object') return errors;
  if (schema.type === 'object' && (typeof body !== 'object' || body === null || Array.isArray(body))) {
    errors.push({ field: '(schema)', expected: 'object', actual: body === null ? 'null' : typeof body });
    return errors;
  }
  for (const key of schema.required || []) {
    if (body == null || !(key in body)) {
      errors.push({ field: key, expected: '(required by schema)', actual: 'missing' });
    }
  }
  for (const [key, propSchema] of Object.entries(schema.properties || {})) {
    if (body == null || !(key in body)) continue;
    const actualType = Array.isArray(body[key]) ? 'array' : typeof body[key];
    if (propSchema.type && actualType !== propSchema.type) {
      errors.push({ field: key, expected: `type ${propSchema.type}`, actual: `type ${actualType}` });
    }
  }
  return errors;
}

if (t.expected_status != null && t.actual.status !== t.expected_status) {
  mismatches.push({ field: 'status', expected: t.expected_status, actual: t.actual.status });
}

mismatches.push(...validateSchema(t.expected_schema, t.actual.body));

const kv = t.expected_key_values || {};
for (const [key, val] of Object.entries(kv)) {
  if (key.endsWith('_semantic')) continue;

  if (key.endsWith('_min') || key.endsWith('_max')) {
    const isMin = key.endsWith('_min');
    const baseField = key.slice(0, -4);
    if (dynamic.has(baseField) || dynamic.has(key)) continue;
    const actualVal = get(t.actual.body, baseField);
    const numActual = Number(actualVal);
    const numExpected = Number(val);
    const ok = actualVal != null && !isNaN(numActual) && (isMin ? numActual >= numExpected : numActual <= numExpected);
    if (!ok) {
      mismatches.push({ field: baseField, expected: `${isMin ? '>=' : '<='} ${val}`, actual: actualVal });
    }
    continue;
  }

  if (dynamic.has(key)) continue;
  const actualVal = get(t.actual.body, key);
  if (JSON.stringify(actualVal) !== JSON.stringify(val)) {
    mismatches.push({ field: key, expected: val, actual: actualVal });
  }
}

const hasSemanticAssertion = Object.keys(kv).some(k => k.endsWith('_semantic'));
const deterministic_verdict = (mismatches.length === 0 && !hasSemanticAssertion) ? 'PASS' : 'AMBIGUOUS';

return { json: { ...t, deterministic_verdict, mismatches } };

