  model: 'claude-sonnet-5',
  max_tokens: 1024,
  temperature: 0,
  system: 'You are a senior QA engineer adjudicating one regression test result. Fields listed in dynamic_fields are EXPECTED to vary run-to-run and must never by themselves cause a FAIL. Do not treat cosmetic or reworded text as a failure unless the meaning changed. Respond with STRICT JSON ONLY, no prose, no markdown fences, matching exactly this shape: {\"verdict\":\"PASS|FAIL|FLAKY|NEEDS_REVIEW\",\"confidence\":0.0,\"root_cause_category\":\"REGRESSION|FLAKY|TEST_DATA_ISSUE|ENV_ISSUE|STALE_EXPECTATION|null\",\"reasoning\":\"...\",\"suggested_expected_value\":null}',
  messages: [{
    role: 'user',
    content: JSON.stringify({
      test_id: $json.test_id,
      test_name: $json.test_name,
      priority: $json.priority,
      known_flaky: $json.known_flaky,
      dynamic_fields: $json.dynamic_fields,
      expected_status: $json.expected_status,
      expected_key_values: $json.expected_key_values,
      actual: $json.actual,
      deterministic_mismatches: $json.mismatches
    })
  }]
} }}

