let verdict;
try {
  const text = ($json.content && $json.content[0] && $json.content[0].text) || '{}';
  const clean = text.replace(/```json|```/g, '').trim();
  verdict = JSON.parse(clean);
} catch (e) {
  verdict = { verdict: 'NEEDS_REVIEW', confidence: 0, root_cause_category: 'ENV_ISSUE', reasoning: 'AI response could not be parsed; flagged for manual review.', suggested_expected_value: null };
}
const testContext = $('Needs AI Review?').item.json;
return { json: { ...testContext, ai_verdict: verdict } };

const item = $json;
let final;
if (item.ai_verdict) {
  final = {
    test_id: item.test_id,
    verdict: item.ai_verdict.verdict,
    source: 'ai',
    confidence: item.ai_verdict.confidence,
    root_cause_category: item.ai_verdict.root_cause_category,
    reasoning: item.ai_verdict.reasoning,
    suggested_expected_value: item.ai_verdict.suggested_expected_value,
    visual_diff_description: item.ai_verdict.visual_diff_description || null,
    mismatches: item.mismatches || [],
    priority: item.priority,
    known_flaky: item.known_flaky,
    run_id: item.run_id,
    build_id: item.build_id
  };
} else {
  final = {
    test_id: item.test_id,
    verdict: 'PASS',
    source: 'deterministic',
    confidence: 1,
    root_cause_category: null,
    reasoning: 'All deterministic assertions passed; no AI call was needed.',
    suggested_expected_value: null,
    visual_diff_description: null,
    mismatches: [],
    priority: item.priority,
    known_flaky: item.known_flaky,
    run_id: item.run_id,
    build_id: item.build_id
  };
}
return { json: final };

const results = $('Batch Controller').all().map(i => i.json);
const history = $input.all().map(i => i.json);
const runInfo = $('Initialize Run').first().json;
const staticData = $getWorkflowStaticData('node');
const skipped = staticData.skipped || [];

const counts = { pass: 0, fail: 0, flaky: 0, needs_review: 0 };
for (const r of results) {
  if (r.verdict === 'PASS') counts.pass++;
  else if (r.verdict === 'FLAKY') counts.flaky++;
  else if (r.verdict === 'NEEDS_REVIEW') counts.needs_review++;
  else counts.fail++;
}

const failures = results.filter(r => r.verdict === 'FAIL');
const clusters = {};
for (const f of failures) {
  const key = f.root_cause_category || 'UNKNOWN';
  clusters[key] = clusters[key] || [];
  clusters[key].push(f);
}

const criticalFail = results.some(r => r.priority === 'critical' && (r.verdict === 'FAIL' || r.verdict === 'NEEDS_REVIEW'));

// --- Cross-run pattern intelligence ---
const historyByTest = {};
for (const h of history) {
  historyByTest[h.test_id] = historyByTest[h.test_id] || [];
  historyByTest[h.test_id].push(h);
}

const chronic_flaky = [];
const recurring_issues = [];
for (const r of results) {
  const priorRuns = (historyByTest[r.test_id] || []).slice(0, 5);
  const flakyCount = priorRuns.filter(h => h.verdict === 'FLAKY').length + (r.verdict === 'FLAKY' ? 1 : 0);
  if (flakyCount >= 3) {
    chronic_flaky.push({ test_id: r.test_id, flaky_runs: flakyCount, window: priorRuns.length + 1 });
  }
  if (r.verdict === 'FAIL') {
    const priorSameCause = priorRuns.filter(h => h.verdict === 'FAIL' && h.root_cause_category === r.root_cause_category);
    if (priorSameCause.length >= 2) {
      const earliest = priorSameCause[priorSameCause.length - 1];
      recurring_issues.push({
        test_id: r.test_id,
        root_cause_category: r.root_cause_category,
        occurrences: priorSameCause.length + 1,
        first_seen_build: earliest.build_id || earliest.run_id
      });
    }
  }
}

// --- Tiered autonomy: classify stale-expectation suggestions ---
const PROTECTED_FIELD_PATTERN = /price|total|subtotal|discount|amount|cost|balance|currency/i;
const AUTO_APPLY_CONFIDENCE = 0.95;
const suggested_updates = { auto_apply: [], manual_review: [] };
for (const r of results) {
  if (r.root_cause_category !== 'STALE_EXPECTATION' || r.suggested_expected_value == null) continue;
  const singleMismatch = (r.mismatches || []).length === 1 ? r.mismatches[0] : null;
  const entry = {
    test_id: r.test_id,
    field: singleMismatch ? singleMismatch.field : null,
    old_expected: singleMismatch ? singleMismatch.expected : null,
    suggested_expected: r.suggested_expected_value,
    reasoning: r.reasoning,
    confidence: r.confidence,
    run_id: r.run_id
  };
  const eligible = !!singleMismatch
    && r.priority !== 'critical'
    && (r.confidence || 0) >= AUTO_APPLY_CONFIDENCE
    && !PROTECTED_FIELD_PATTERN.test(singleMismatch.field || '');
  if (eligible) suggested_updates.auto_apply.push(entry);
  else suggested_updates.manual_review.push(entry);
}

return [{ json: {
  run_id: results[0] ? results[0].run_id : runInfo.run_id,
  build_id: runInfo.build_id,
  counts, total: results.length, failures, clusters, skipped, critical_fail: criticalFail,
  chronic_flaky, recurring_issues, suggested_updates
} }];

