let summary;
try {
  const text = ($json.content && $json.content[0] && $json.content[0].text) || '{}';
  summary = JSON.parse(text.replace(/```json|```/g, '').trim());
} catch (e) {
  summary = { headline: 'Summary unavailable - AI parsing failed', top_risks: [], narrative: 'The executive summary could not be generated automatically; please review results manually.' };
}
const agg = $('Compute Risk Score').first().json;
return [{ json: { ...agg, ...summary } }];

function hashStr(s) {
  let h = 5381;
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h) + s.charCodeAt(i);
  return Math.abs(h).toString(36);
}
const data = $json;
const items = [];
for (const [category, failures] of Object.entries(data.clusters || {})) {
  const testIds = failures.map(f => f.test_id).sort().join(',');
  const label = `qa-cluster-${category.toLowerCase().replace(/[^a-z0-9]+/g, '-')}-${hashStr(testIds)}`;
  items.push({ json: { run_id: data.run_id, root_cause_category: category, failures, count: failures.length, cluster_label: label } });
}
return items;

