const body = $json;
const cases = (body && body.test_cases) || (Array.isArray(body) ? body : []);
return cases.map(tc => ({ json: {
  ...tc,
  tags: Array.isArray(tc.tags) ? tc.tags.join(',') : (tc.tags || ''),
  active: String(tc.active)
} }));

const agg = $json;
let score = 0;
score += agg.counts.fail * 15;
score += agg.counts.needs_review * 8;
score += agg.counts.flaky * 3;
score += (agg.recurring_issues || []).length * 12;
score += (agg.chronic_flaky || []).length * 5;
if (agg.critical_fail) score += 40;
score = Math.min(100, score);

let risk_rating;
if (agg.critical_fail || score >= 70) risk_rating = 'CRITICAL';
else if (score >= 40) risk_rating = 'HIGH';
else if (score >= 15) risk_rating = 'MEDIUM';
else risk_rating = 'LOW';

return [{ json: { ...agg, risk_score: score, risk_rating } }];

function sqlStr(v) {
  if (v == null) return 'NULL';
  if (typeof v === 'object') return `'${JSON.stringify(v).replace(/'/g, "''")}'::jsonb`;
  return `'${String(v).replace(/'/g, "''")}'::jsonb`;
}
function sqlLiteral(v) {
  return v == null ? 'NULL' : `'${String(v).replace(/'/g, "''")}'`;
}
const agg = $json;
const rows = [];
for (const s of ((agg.suggested_updates && agg.suggested_updates.auto_apply) || [])) rows.push({ ...s, auto_applied: true, reviewed: true });
for (const s of ((agg.suggested_updates && agg.suggested_updates.manual_review) || [])) rows.push({ ...s, auto_applied: false, reviewed: false });

return rows.map(s => ({ json: {
  run_id_sql: sqlLiteral(s.run_id),
  test_id_sql: sqlLiteral(s.test_id),
  field_sql: sqlLiteral(s.field),
  old_expected_sql: sqlStr(s.old_expected),
  suggested_expected_sql: sqlStr(s.suggested_expected),
  reasoning_sql: sqlLiteral(s.reasoning),
  confidence: s.confidence == null ? 'NULL' : Number(s.confidence),
  auto_applied: s.auto_applied,
  reviewed: s.reviewed
} }));

const agg = $json;
const autoApply = (agg.suggested_updates && agg.suggested_updates.auto_apply) || [];
if (!autoApply.length) return [];

const sourceRows = $('Validate & Filter Tests').all().map(i => i.json);
const byTestId = Object.fromEntries(sourceRows.map(r => [r.test_id, r]));

const out = [];
for (const s of autoApply) {
  const row = byTestId[s.test_id];
  if (!row || !s.field) continue;
  const kv = { ...(row.expected_key_values || {}), [s.field]: s.suggested_expected };
  out.push({ json: { test_id: s.test_id, expected_key_values: JSON.stringify(kv) } });
}
return out;

function sqlLiteral(v) {
  return v == null ? 'NULL' : `'${String(v).replace(/'/g, "''")}'`;
}
const results = $('Batch Controller').all().map(i => i.json);
return results.map(r => ({ json: {
  run_id_sql: sqlLiteral(r.run_id),
  test_id_sql: sqlLiteral(r.test_id),
  build_id_sql: sqlLiteral(r.build_id),
  verdict_sql: sqlLiteral(r.verdict),
  root_cause_category_sql: sqlLiteral(r.root_cause_category),
  priority_sql: sqlLiteral(r.priority)
} }));

